// WalletCard.js - Tarjeta individual para mostrar cada billetera
// Versión más profesional, sin emojis excesivos

import React from 'react';
import './WalletCard.css';

const WalletCard = ({ name, type, balance, color = 'purple' }) => {
  // Icono simple según el tipo (usando solo texto o ícono minimalista)
  const getIconText = () => {
    switch (type) {
      case 'Ahorro':
        return 'AH';
      case 'Gastos diarios':
        return 'GD';
      case 'Compras':
        return 'CP';
      case 'Transporte':
        return 'TR';
      case 'Inversión':
        return 'IN';
      default:
        return 'BP';
    }
  };

  // Formatear número a moneda COP
  const formatCurrency = (value) => {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0
    }).format(value);
  };

  // Formatear nombre de tipo
  const formatType = (type) => {
    const types = {
      'Ahorro': 'Cuenta de ahorro',
      'Gastos diarios': 'Gastos diarios',
      'Compras': 'Compras online',
      'Transporte': 'Movilidad',
      'Inversión': 'Portafolio inversión'
    };
    return types[type] || type;
  };

  return (
    <div className={`wallet-card wallet-card-${color}`}>
      <div className="wallet-card-header">
        <div className="wallet-icon-minimal">
          <span>{getIconText()}</span>
        </div>
        <div className="wallet-info">
          <h4 className="wallet-name">{name}</h4>
          <p className="wallet-type">{formatType(type)}</p>
        </div>
      </div>
      
      <div className="wallet-balance">
        <span className="balance-label">Balance disponible</span>
        <span className="balance-value">{formatCurrency(balance)}</span>
      </div>
      
      <div className="wallet-actions">
        <button className="wallet-btn recargar">Recargar</button>
        <button className="wallet-btn transferir">Transferir</button>
        <button className="wallet-btn retirar">Retirar</button>
      </div>
    </div>
  );
};

export default WalletCard;
